"use client";

import { motion } from "framer-motion";
import { ReactNode } from "react";

interface AnimatedSectionProps {
  children: ReactNode;
  className?: string;
  delay?: number;
}

export function AnimatedSection({ children, className = "", delay = 0 }: AnimatedSectionProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-80px" }}
      transition={{ duration: 0.7, delay, ease: "easeOut" }}
      className={className}
    >
      {children}
    </motion.div>
  );
}

export function SectionDivider() {
  return (
    <motion.div
      initial={{ scaleX: 0 }}
      whileInView={{ scaleX: 1 }}
      viewport={{ once: true }}
      transition={{ duration: 0.8, ease: "easeOut" }}
      className="w-20 h-px bg-gradient-to-r from-transparent via-gold to-transparent mx-auto my-4"
    />
  );
}

export function SectionHeading({ subtitle, title }: { subtitle: string; title: string }) {
  return (
    <div className="text-center mb-16">
      <AnimatedSection>
        <p className="text-gold text-xs tracking-[0.3em] uppercase mb-4">{subtitle}</p>
      </AnimatedSection>
      <AnimatedSection delay={0.1}>
        <h2 className="font-serif text-4xl md:text-5xl text-warm-white mb-6">{title}</h2>
      </AnimatedSection>
      <SectionDivider />
    </div>
  );
}

export function GoldButton({
  children,
  onClick,
  className = "",
  type = "button",
}: {
  children: ReactNode;
  onClick?: () => void;
  className?: string;
  type?: "button" | "submit";
}) {
  return (
    <motion.button
      whileHover={{ scale: 1.03 }}
      whileTap={{ scale: 0.97 }}
      type={type}
      onClick={onClick}
      className={`px-8 py-3 bg-gold text-charcoal-deep font-semibold text-sm tracking-wider uppercase hover:bg-gold-light transition-colors duration-300 rounded-sm ${className}`}
    >
      {children}
    </motion.button>
  );
}

export function OutlineButton({
  children,
  onClick,
  className = "",
}: {
  children: ReactNode;
  onClick?: () => void;
  className?: string;
}) {
  return (
    <motion.button
      whileHover={{ scale: 1.03 }}
      whileTap={{ scale: 0.97 }}
      onClick={onClick}
      className={`px-8 py-3 border border-gold/50 text-gold text-sm tracking-wider uppercase hover:bg-gold hover:text-charcoal-deep transition-all duration-300 rounded-sm ${className}`}
    >
      {children}
    </motion.button>
  );
}
